// Set the URL to summarize here
const url = "https://www.geektime.co.il/one-more-thing-macintosh-apple-50th-anniversary";
return [{ json: { url } }];

const input = $input.first().json;
const url = $('Set URL').first().json.url || "";

// Check if Jina returned usable content
let jinaText = input.data || input.html || input.body || input.content || input.response || "";
if (typeof jinaText !== "string") jinaText = String(jinaText);

// Jina returns markdown — strip common markdown artifacts but keep the text
jinaText = jinaText
  .replace(/!\[[^\]]*\]\([^)]*\)/g, "")   // remove images
  .replace(/\[[^\]]*\]\([^)]*\)/g, (m) => { // keep link text, drop URL
    const text = m.match(/\[([^\]]*)\]/);
    return text ? text[1] : "";
  })
  .replace(/^#{1,6}\s+/gm, "")             // remove heading markers
  .replace(/\*\*([^*]+)\*\*/g, "$1")       // remove bold
  .replace(/\*([^*]+)\*/g, "$1")           // remove italic
  .replace(/^[\-\*]\s+/gm, "")             // remove list markers
  .replace(/\n{3,}/g, "\n\n")              // collapse newlines
  .trim();

const hasError = !!(input.error || input.statusCode >= 400);
const tooShort = jinaText.length < 200;

if (hasError || tooShort) {
  // Pass through to fallback HTML extraction
  return [{ json: { jinaFailed: true, jinaLength: jinaText.length, url } }];
}

// Jina succeeded — extract title from first line if it looks like a title
let pageTitle = "";
const lines = jinaText.split("\n").filter(l => l.trim());
if (lines.length > 0 && lines[0].length < 200) {
  pageTitle = lines[0].trim();
}

const MAX_LENGTH = 8000;
let article = jinaText;
if (article.length > MAX_LENGTH) {
  article = article.substring(0, MAX_LENGTH) + "... [truncated]";
}

return [{ json: { 
  article, 
  url, 
  pageTitle, 
  originalLength: jinaText.length, 
  extractedLength: article.length, 
  valid: true,
  jinaFailed: false,
  source: "jina"
} }];

const inputData = $input.first().json;
const html = inputData.data || inputData.html || inputData.body || inputData.content || inputData.response || "";
const url = $('Set URL').first().json.url || "";

if (!html) {
  return [{ json: { error: "No HTML content found", article: "", url, pageTitle: "", valid: false } }];
}

// Decode HTML entities helper
function decodeEntities(str) {
  return str
    .replace(/&#x([0-9A-Fa-f]+);/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
    .replace(/&#([0-9]+);/g, (_, dec) => String.fromCharCode(parseInt(dec, 10)))
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, " ");
}

let pageTitle = "";
try {
  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) pageTitle = decodeEntities(titleMatch[1]).trim();
} catch(e) {}

const MAX_LENGTH = 8000;
let text = "";

try {
  const matches = html.match(/<(p|h[1-6])[^>]*>([\s\S]*?)<\/(p|h[1-6])>/gi);
  if (matches) {
    text = matches
      .map(m => decodeEntities(m.replace(/<[^>]+>/g, "")).trim())
      .filter(t => t.length > 5)
      .join("\n\n");
  }
} catch (e) {}

if (text.length < 100) {
  try {
    const jsonBlocks = html.match(/<script[^>]+type=["']application\/(ld\+json|json)["'][^>]*>([\s\S]*?)<\/script>/gi);
    if (jsonBlocks) {
      for (let block of jsonBlocks) {
        try {
          const clean = block.replace(/<script[^>]*>/i, "").replace(/<\/script>/i, "").trim();
          const parsed = JSON.parse(clean);
          const findText = (obj) => {
            if (!obj || typeof obj !== "object") return null;
            if (obj.articleBody && typeof obj.articleBody === "string") return obj.articleBody;
            if (obj.text && typeof obj.text === "string" && obj.text.length > 100) return obj.text;
            if (Array.isArray(obj)) { for (const el of obj) { const r = findText(el); if (r) return r; } }
            else { for (const key of Object.keys(obj)) { const r = findText(obj[key]); if (r) return r; } }
            return null;
          };
          const result = findText(parsed);
          if (result) { text = decodeEntities(result); break; }
        } catch (err) {}
      }
    }
  } catch (e) {}
}

if (!text || text.length < 200) {
  return [{ json: { 
    error: "Article body not found or too short (likely JS-rendered or blocked). Extracted only " + text.length + " chars.", 
    article: text, 
    url, 
    pageTitle, 
    valid: false 
  } }];
}

if (text.length > MAX_LENGTH) {
  text = text.substring(0, MAX_LENGTH) + "... [truncated]";
}

return [{ json: { article: text, url, pageTitle, originalLength: html.length, extractedLength: text.length, valid: true, source: "fallback" } }];

const url = $('Set URL').first().json.url || "";
const pageTitle = $json.pageTitle || "";
const error = $json.error || "Could not extract article content";

const displayName = pageTitle || url || "Unknown";
const link = url ? `<${url}|${displayName}>` : displayName;

const text = `:warning: *Could not summarize article*\n\n${link}\n\n_Reason: ${error}_\n\n_Tried both Jina Reader and direct HTML extraction. The page may be JS-rendered, paywalled, or blocking automated access. Try a direct article URL instead of an aggregator like MSN._`;

return [{ json: { text } }];

const text = $json.article || "";
const url = $json.url || "";
const pageTitle = $json.pageTitle || "";

if (!text) {
  return [{ json: { language: "en", article: "", url, pageTitle } }];
}

// Check both article text AND page title for Hebrew
const combinedText = text + " " + pageTitle;
const hebrewMatches = combinedText.match(/[\u0590-\u05FF]/g) || [];
const hebrewRatio = hebrewMatches.length / combinedText.length;

// Check if URL is from known Hebrew sites
const hebrewDomains = ['walla.co.il', 'ynet.co.il', 'mako.co.il', 'haaretz.co.il', 'haaretz.com', 'globes.co.il', 'calcalist.co.il', 'maariv.co.il', 'israelhayom.co.il', 'kan.org.il', 'now14.co.il', 'ice.co.il', 'sport5.co.il', 'geektime.co.il', 'themarker.com', 'timeout.co.il', 'n12.co.il', 'reshet.tv', 'news.walla.co.il', 'e.walla.co.il'];
const isHebrewDomain = hebrewDomains.some(d => url.includes(d));

// Check page title for Hebrew
const titleHebrewMatches = pageTitle.match(/[\u0590-\u05FF]/g) || [];
const titleHasHebrew = titleHebrewMatches.length > 3;

const language = (hebrewRatio > 0.1 || isHebrewDomain || titleHasHebrew) ? "he" : "en";

console.log(`Language: ${language}, ratio: ${hebrewRatio.toFixed(3)}, hebrewDomain: ${isHebrewDomain}, titleHebrew: ${titleHasHebrew}`);

return [{ json: { language, article: text, url, pageTitle } }];

console.log("=== VALIDATOR START ===");

// Try to get language from Language Detector
let language = "en";
let url = "";
let pageTitle = "";
try {
  const upstream = $('Language Detector1').first().json;
  language = upstream.language || "en";
  url = upstream.url || "";
  pageTitle = upstream.pageTitle || "";
} catch(e) {
  console.log("Could not read Language Detector:", e.message);
}

let raw = $json.output || $json.text || $json.content || "";
if (typeof raw !== "string") raw = JSON.stringify(raw);

console.log("Raw length:", raw.length);
console.log("Raw first 500:", raw.slice(0, 500));

// Clean markdown fences and normalize quotes
let s = raw
  .replace(/```json\s*/gi, "")
  .replace(/```\s*/g, "")
  .replace(/[\u2018\u2019]/g, "'")
  .replace(/[\u201C\u201D]/g, '"')
  .trim();

// Extract JSON object from surrounding text
const jsonStart = s.indexOf('{');
const jsonEnd = s.lastIndexOf('}');
if (jsonStart !== -1 && jsonEnd > jsonStart) {
  s = s.substring(jsonStart, jsonEnd + 1);
}

let obj = null;

// Attempt 1: Direct parse
try {
  obj = JSON.parse(s);
  if (typeof obj === "string") obj = JSON.parse(obj);
  console.log("Parse attempt 1 OK");
} catch (e) {
  console.log("Parse 1 failed:", e.message);
}

// Attempt 2: Fix trailing commas, newlines
if (!obj) {
  try {
    let fixed = s.replace(/,\s*]/g, "]").replace(/,\s*}/g, "}").replace(/\n/g, " ").replace(/\t/g, " ");
    obj = JSON.parse(fixed);
    console.log("Parse attempt 2 OK");
  } catch (e) {
    console.log("Parse 2 failed:", e.message);
  }
}

// Attempt 3: Truncated JSON repair
if (!obj) {
  try {
    let repair = s;
    const openBrackets = (repair.match(/\[/g) || []).length;
    const closeBrackets = (repair.match(/\]/g) || []).length;
    const openBraces = (repair.match(/\{/g) || []).length;
    const closeBraces = (repair.match(/\}/g) || []).length;
    const quotes = repair.match(/(?<!\\)"/g) || [];
    if (quotes.length % 2 !== 0) repair += '"';
    for (let i = 0; i < (openBrackets - closeBrackets); i++) repair += ']';
    for (let i = 0; i < (openBraces - closeBraces); i++) repair += '}';
    repair = repair.replace(/,\s*]/g, "]").replace(/,\s*}/g, "}");
    obj = JSON.parse(repair);
    console.log("Parse attempt 3 (repair) OK");
  } catch (e) {
    console.log("Parse 3 failed:", e.message);
  }
}

// Attempt 4: Regex salvage
if (!obj || typeof obj !== "object") {
  const titleMatch = s.match(/"title"\s*:\s*"((?:[^"\\]|\\.)*)"/);
  const bulletMatches = [...s.matchAll(/"((?:[^"\\]|\\.){10,})"/g)]
    .map(m => m[1])
    .filter(t => !t.match(/^(title|bullets|language|url|Short title|Point \d)$/i) && t.length > 15);
  if (titleMatch && bulletMatches.length >= 2) {
    obj = { title: titleMatch[1], bullets: bulletMatches.slice(0, 5) };
    console.log("Regex salvage OK");
  }
}

if (!obj) {
  return [{ json: { error: "Failed to parse AI output", raw: s.slice(0, 500), language, url } }];
}

// GUARD: Check if the AI returned an error title (refused to summarize)
if (obj.title && obj.title.toLowerCase().includes("error")) {
  return [{ json: { error: "AI could not summarize: " + obj.title, raw: "", language, url, pageTitle } }];
}

let title = obj.title || "Summary";
let bullets = Array.isArray(obj.bullets) ? obj.bullets : [];

bullets = bullets
  .map(b => typeof b !== "string" ? String(b) : b)
  .map(b => b.replace(/\\n/g, " ").replace(/\\t/g, " ").replace(/\\"/g, '"').trim())
  .filter(b => b.length > 5);

if (bullets.length > 5) bullets = bullets.slice(0, 5);
const defaultBullet = language === "he" ? "לא נמצאו פרטים נוספים." : "No further details available.";
while (bullets.length < 5) bullets.push(defaultBullet);

console.log("=== VALIDATOR OK: title:", title, "bullets:", bullets.length);
return [{ json: { title, bullets, language, url, pageTitle, source: language === "he" ? "OpenRouter" : "Local" } }];

const input = $json || {};
const title = input.title || null;
const bullets = input.bullets || null;
const error = input.error || null;
const raw = input.raw || "";
const url = input.url || "";
const pageTitle = input.pageTitle || "";
const language = input.language || "en";
const source = input.source || "Unknown";

if (error && (!bullets || !Array.isArray(bullets) || bullets.length === 0)) {
  const errorMsg = language === "he" ? "שגיאה בעיבוד המאמר" : "Error processing article";
  const sourceText = language === "he" ? "מקור:" : "Source:";
  return [{
    json: {
      text: `⚠️ ${errorMsg}\n\n${sourceText} ${url ? `<${url}|${url}>` : "Unknown"}\n\n\`\`\`\n${raw?.slice(0, 500) || "No content"}\n\`\`\``
    }
  }];
}

// Decode HTML entities
function decodeEntities(str) {
  return str
    .replace(/&#x([0-9A-Fa-f]+);/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
    .replace(/&#([0-9]+);/g, (_, dec) => String.fromCharCode(parseInt(dec, 10)))
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, " ");
}

let cleanTitle = decodeEntities(String(title || "Summary"))
  .replace(/^["']|["']$/g, "")
  .replace(/[.,"]+$/, "")
  .replace(/automated with this n8n workflow/i, "")
  .trim();

let displayPageTitle = pageTitle ? decodeEntities(pageTitle) : "";

let cleanBullets = (Array.isArray(bullets) ? bullets : [])
  .map(b => String(b).trim())
  .filter(b => b && !/automated with this n8n workflow/i.test(b))
  .map(b => {
    let cleaned = b.replace(/^["']|["']$/g, "").replace(/^[•\-\*\s]+/, "").trim();
    cleaned = cleaned.replace(/\.{2,}/g, ".");
    if (cleaned.length > 0) cleaned = cleaned.charAt(0).toUpperCase() + cleaned.slice(1);
    if (!/[.!?]$/.test(cleaned) && !/[׃׀]$/.test(cleaned)) cleaned += ".";
    return cleaned;
  })
  .filter(Boolean)
  .slice(0, 5);

const defaultBullet = language === "he" ? "לא נמצאו פרטים נוספים." : "No further details available.";
while (cleanBullets.length < 5) cleanBullets.push(defaultBullet);

const RTL = "\u200F";
const summaryLabel = language === "he" ? "סיכום:" : "Summary:";

const titleLink = url ? `<${url}|${cleanTitle}>` : cleanTitle;
const summaryLine = language === "he"
  ? `:brain: ${summaryLabel} ${RTL}${titleLink}${RTL}`
  : `:brain: ${summaryLabel} ${titleLink}`;

let parts;
if (language === "he") {
  parts = [
    summaryLine,
    "",
    ...cleanBullets.map((b, i) => `${i + 1}. ${RTL}${b}${RTL}`),
    ""
  ];
} else {
  parts = [
    summaryLine,
    "",
    ...cleanBullets.map(b => `• ${b}`),
    ""
  ];
}

return [{ json: { text: parts.join("\n") } }];
